#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <openssl/rsa.h>
#include <openssl/pem.h>
#include <openssl/err.h>
#include <openssl/sha.h>
#include <openssl/rand.h>
#include <time.h>

#define KEY_SIZE 512
#define NONCE_SIZE 32

// Structure to hold authentication data
typedef struct {
 unsigned char nonce[NONCE_SIZE];
 char timestamp[64];
 unsigned char *signature;
 size_t sig_len;
} Challenge;

typedef struct {
 RSA *public_key;
 RSA *private_key;
} KeyPair;

// Handle OpenSSL errors
void handle_errors() {
 ERR_print_errors_fp(stderr);
 abort();
}

// Generate RSA key pair
KeyPair* generate_keypair() {
 KeyPair *keys = malloc(sizeof(KeyPair));
 if (!keys) return NULL;

 // Generate RSA key pair
 keys->private_key = RSA_generate_key(KEY_SIZE, RSA_F4, NULL, NULL);
 if (!keys->private_key) {
 handle_errors();
 }

 // Extract public key from key pair
 keys->public_key = RSAPublicKey_dup(keys->private_key);
 if (!keys->public_key) {
 handle_errors();
 }

 return keys;
}

// Generate random nonce for challenge
void generate_nonce(unsigned char *nonce, int length) {
 if (RAND_bytes(nonce, length) != 1) {
 handle_errors();
 }
}

// Create challenge (server-side)
Challenge* create_challenge() {
 Challenge *challenge = malloc(sizeof(Challenge));
 if (!challenge) return NULL;

 // Generate random nonce
 generate_nonce(challenge->nonce, NONCE_SIZE);

 // Add timestamp
 time_t now = time(NULL);
 strftime(challenge->timestamp, sizeof(challenge->timestamp), 
 "%Y-%m-%d %H:%M:%S", localtime(&now));

 challenge->signature = NULL;
 challenge->sig_len = 0;

 return challenge;
}

// Hash challenge data
unsigned char* hash_challenge(Challenge *challenge, unsigned int *hash_len) {
 unsigned char *hash = malloc(SHA256_DIGEST_LENGTH);
 if (!hash) return NULL;

 // Combine nonce and timestamp
 unsigned char data[NONCE_SIZE + 64];
 memcpy(data, challenge->nonce, NONCE_SIZE);
 memcpy(data + NONCE_SIZE, challenge->timestamp, strlen(challenge->timestamp));

 // SHA-256 hash
 SHA256(data, NONCE_SIZE + strlen(challenge->timestamp), hash);
 *hash_len = SHA256_DIGEST_LENGTH;

 return hash;
}

// Sign challenge (client-side)
int sign_challenge(Challenge *challenge, RSA *private_key, 
 unsigned char **signature, unsigned int *sig_len) {
 unsigned int hash_len;
 unsigned char *hash = hash_challenge(challenge, &hash_len);

 if (!hash) return 0;

 // Allocate memory for signature
 *signature = malloc(RSA_size(private_key));
 if (!*signature) {
 free(hash);
 return 0;
 }

 // Sign the hash
 *sig_len = RSA_sign(NID_sha256, hash, hash_len, *signature, sig_len, private_key);

 free(hash);

 if (!*sig_len) {
 free(*signature);
 *signature = NULL;
 return 0;
 }

 challenge->signature = *signature;
 challenge->sig_len = *sig_len;

 return 1;
}

// Verify signature (server-side)
int verify_signature(Challenge *challenge, RSA *public_key) {
 unsigned int hash_len;
 unsigned char *hash = hash_challenge(challenge, &hash_len);

 if (!hash) return 0;

 int result = RSA_verify(NID_sha256, hash, hash_len, 
 challenge->signature, challenge->sig_len, public_key);

 free(hash);

 return result;
}

// Print hex bytes
void print_hex(const char *label, unsigned char *data, size_t len) {
 printf("%s: ", label);
 for (size_t i = 0; i < len && i < 16; i++) {
 printf("%02x", data[i]);
 }
 printf("...\n");
}

// Main authentication demonstration
int main() {
 printf("==============================================\n");
 printf(" Remote User Authentication using RSA\n");
 printf("==============================================\n\n");

 // Initialize OpenSSL
 OpenSSL_add_all_algorithms();
 ERR_load_crypto_strings();

 // Step 1: Generate client key pair
 printf("[STEP 1] Generating client key pair...\n");
 KeyPair *client_keys = generate_keypair();
 printf(" Client keys generated (RSA %d-bit)\n\n", KEY_SIZE);

 // Step 2: Server creates challenge
 printf("[STEP 2] Server generating challenge...\n");
 Challenge *challenge = create_challenge();
 print_hex(" Nonce", challenge->nonce, NONCE_SIZE);
 printf(" Timestamp: %s\n\n", challenge->timestamp);

 // Step 3: Client signs the challenge
 printf("[STEP 3] Client signing challenge with private key...\n");
 unsigned char *signature = NULL;
 unsigned int sig_len = 0;

 if (sign_challenge(challenge, client_keys->private_key, &signature, &sig_len)) {
 print_hex(" Signature", signature, sig_len);
 printf(" Signature length: %u bytes\n\n", sig_len);
 } else {
 printf(" ERROR: Signing failed!\n");
 return 1;
 }

 // Step 4: Server verifies signature
 printf("[STEP 4] Server verifying signature with client public key...\n");
 int is_valid = verify_signature(challenge, client_keys->public_key);

 if (is_valid) {
 printf(" ✓ SIGNATURE VALID\n");
 printf("\n ===========================================\n");
 printf(" ✓ AUTHENTICATION SUCCESSFUL!\n");
 printf(" ===========================================\n");
 printf(" The user proved ownership of the private key\n");
 printf(" without transmitting it over the network.\n");
 } else {
 printf(" ✗ SIGNATURE INVALID\n");
 printf("\n ✗ AUTHENTICATION FAILED!\n");
 }

 // Cleanup
 printf("\n[CLEANUP] Freeing memory...\n");
 RSA_free(client_keys->private_key);
 RSA_free(client_keys->public_key);
 free(client_keys);
 free(challenge);
 free(signature);
 EVP_cleanup();
 ERR_free_strings();

 printf(" Done.\n");

 return is_valid ? 0 : 1;
}
